example.code:
import DataLoader from 'dataloader';

// Per-request factory — call in context setup, not at module level
export const createLoaders = () => ({
  userById: new DataLoader<string, User | null>(async (ids) => {
    const users = await db.users.findMany({ where: { id: { in: [...ids] } } });
    const map = new Map(users.map(u => [u.id, u]));
    // CRITICAL: return in same order as input ids
    return ids.map(id => map.get(id) ?? null);
  }),

  // 1:N grouping pattern
  ordersByUserId: new DataLoader<string, Order[]>(async (userIds) => {
    const orders = await db.orders.findMany({
      where: { userId: { in: [...userIds] } }
    });
    const grouped = new Map<string, Order[]>();
    for (const order of orders) {
      const arr = grouped.get(order.userId) ?? [];
      arr.push(order);
      grouped.set(order.userId, arr);
    }
    return userIds.map(id => grouped.get(id) ?? []);
  }),
});

// In resolver
resolve: (order) => ctx.loaders.userById.load(order.userId)

# Users service
type User @key(fields: "id") {
  id: ID!
  name: String!
  email: String!
}

# Orders service — extends User without importing it
extend type User @key(fields: "id") {
  id: ID! @external
  orders: [Order!]!
}
